                lis.push(indexMap.get(num));
            } else {
                lis[pos] = indexMap.get(num);
            }
        }
    }

    return target.length - lis.length;
}

function lowerBound(arr, target) {
    let low = 0;
    let high = arr.length;

    while (low < high) {
        const mid = Math.floor((low + high) / 2);
        if (arr[mid] < target) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }

    return low;
}
